import{_ as n}from"./Menu.b66ac8de.js";import{u as a}from"./composables.7a114ca2.js";import{r as t,a as u,e,b as l,f as d,i as s,o as c}from"./entry.04c0a871.js";const p=""+new URL("ideation-p.834b9c8f.jpg",import.meta.url).href,m=""+new URL("idv-poireauteur.818a2d85.png",import.meta.url).href,v={class:"banniere"},f=d('<div class="margium-l marge-haute-l"><div class="espacium"><h1>Le Poireauteur </h1><div class="colonnes"><div class="colonne"><div class="projettitre">Contexte</div> Projet de Master 1 \xE0 l&#39;UPHF<br> f\xE9vrier 2021 \xE0 avril 2021 </div><div class="colonne"><div class="projettitre">\xC9quipe</div><a href="https://fedou-eleonore.netlify.app/" target="_blank">\xC9l\xE9onore F\xE9dou</a>,<br><a href="https://www.behance.net/VianneyChantry" target="_blank">Vianney Chantry</a>,<br><a href="https://selenagruber.netlify.app/" target="_blank">Selena Gruber</a></div><div class="colonne"><div class="projettitre">typologie de projet</div> Id\xE9ation, design graphique, UI design </div><div class="colonne"></div></div></div></div>',1),h=e("article",{class:"margium-l marge-haute-l marge-basse-l"},[e("div",{class:"espacium"},[e("div",{class:"coldroite"},[e("p",null,"Avez-vous d\xE9j\xE0 connu une nette sensation d'ennui lorsque vous \xE9tiez dans une file d'attente ? Vous en avez marre de perdre votre temps sur les r\xE9seaux sociaux ? Le Poireauteur vous propose de poireauter utile ! Il met profit ces moments d'attente et d'ennui en vous faisant d\xE9couvrir un contenu artistique et culturel, qui vous sortira de votre zone de confort. Gratuite, rapide et sans compte, sentez-vous libre d'utiliser notre application comme bon vous semble\u202F! Notre but n'est pas que vous perdiez votre temps sur notre application, mais plut\xF4t que vous l'optimisiez !"),e("p",null,[s(" Gr\xE2ce au Poireauteur, vous allez \xE9tendre votre culture. Les contenus propos\xE9s sont courts (1-5 min). De plus, le principe d'al\xE9atoire permet de d\xE9couvrir des propos dont vous n'avez pas l'habitude. Cela vous permet de sortir de votre zone de confort et, peut-\xEAtre, vous d\xE9couvrirez une nouvelle passion. Notre application vous permet de d\xE9couvrir des artistes, des \u0153uvres et des lieux culturels, mais aussi, d'approfondir vos connaissances avec des informations compl\xE9mentaires. En effet, chaque page contient un onglet permettant d'en savoir plus sur le sujet abord\xE9. L'application devient un tremplin vous emmenant sur des recherches approfondies."),e("br"),s(" Vous accompagnez lors de vos temps d'attente est la priorit\xE9 du Poireauteur. Le contenu propos\xE9 est donc adapt\xE9 chaque situation. C'est pourquoi nous proposons 3 cat\xE9gories : visuelles, auditif et textuel, qui peuvent se cumuler. Le Poireauteur est alors une application simple et accessible permettant une forme d'acc\xE8s \xF4 la culture. Elle vous permet de rester ouverts d'esprit en tirant avantage de vos temps d'ennui, d'attente.")]),e("h2",null,"Id\xE9ation"),e("p",null," Nous avons r\xE9alis\xE9 des exercices d'id\xE9ations sur le sujet des applications de divertissements. Un \xE9l\xE9ment remarqu\xE9 lors de notre veille sur l'\xE9tat de l'existant \xE9tait le caract\xE8re non-informatif et culturel des applications comme Tiktok, IG TV ou 9GAG. Nous avons pris un positionnement aux antipodes des applications de l'\xE9conomie de l'attention. Nous avons choisi de concevoir une application de divertissements culturels et enrichissant pour des temps d'attente quotidiens comme les files d'attente ou les transports en commun. "),e("img",{src:p,alt:"4 wireframes dessin\xE9 lord d'une session d'id\xE9ation"}),e("p",null," Les wireframes, on \xE9tait con\xE7u avec la m\xE9thode 6 to 1. Elle nous a permis, de pr\xE9senter les id\xE9es de chacun et chacune en ad\xE9quation avec les besoins d'usages. Le sketch 2 a \xE9t\xE9 retenu pour sa proportion \xE0 aller \xE0 l'essentiel en pr\xE9sentant les filtres de format de contenu (vid\xE9o, texte, audio). Ce crit\xE8re a \xE9t\xE9 jug\xE9 le plus pertinent, il permet \xE0 l'utilisateur de s\xE9lectionner les formats qu'il peut consulter facilement en fonction de son environnement (bruyant, s'il a des \xE9couteurs, s'il ne peut pas lire). "),e("h2",null,"Vid\xE9o de promotion"),e("div",{class:"container"},[e("iframe",{class:"video",width:"720",height:"405",src:"https://www.youtube-nocookie.com/embed/N7z5ijqThN8",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture",allowfullscreen:""})]),e("h2",null,"Identit\xE9 visuelle"),e("img",{src:m,loading:"lazy",alt:"identit\xE9 visuelle du Poireauteur"})])])],-1),x={__name:"le-poireauteur",setup(b){const o=t("Le Poireauteur - Lucas Lacroix"),r=t("Gr\xE2ce au Poireauteur, vous allez \xE9tendre votre culture. Les contenus propos\xE9s sont courts (1-5 min). De plus, le principe d'al\xE9atoire permet de d\xE9couvrir des propos dont vous n'avez pas l'habitude.");return a({title:o,meta:[{name:"description",content:r}]}),(_,g)=>{const i=n;return c(),u("div",null,[e("div",v,[l(i),f]),h])}}};export{x as default};
